import React from 'react';
import { BUSINESS_INFO } from '../data';

interface JsonLdProps {
  type: 'LocalBusiness' | 'Breadcrumbs';
  breadcrumbs?: { name: string; url: string }[];
}

export function JsonLd({ type, breadcrumbs }: JsonLdProps) {
  if (type === 'LocalBusiness') {
    const businessSchema = {
      "@context": "https://schema.org",
      "@type": "PlumbingService",
      "name": BUSINESS_INFO.name,
      "image": "https://prideplumbingfl.com/og-image.jpg", // default fallback
      "@id": "https://prideplumbingfl.com/#plumbing-service",
      "url": "https://prideplumbingfl.com",
      "telephone": BUSINESS_INFO.phone,
      "email": BUSINESS_INFO.email,
      "priceRange": "$$",
      "address": {
        "@type": "PostalAddress",
        "streetAddress": "5711 NE 14th Ave Ste 200",
        "addressLocality": "Fort Lauderdale",
        "addressRegion": "FL",
        "postalCode": "33334",
        "addressCountry": "US"
      },
      "geo": {
        "@type": "GeoCoordinates",
        "latitude": 26.1993, // Fort Lauderdale coordinates
        "longitude": -80.1259
      },
      "openingHoursSpecification": {
        "@type": "OpeningHoursSpecification",
        "dayOfWeek": [
          "Monday",
          "Tuesday",
          "Wednesday",
          "Thursday",
          "Friday",
          "Saturday",
          "Sunday"
        ],
        "opens": "00:00",
        "closes": "23:59"
      },
      "areaServed": [
        {
          "@type": "State",
          "name": "Florida"
        }
      ]
    };

    return (
      <script
        id="schema-local-business"
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(businessSchema) }}
      />
    );
  }

  if (type === 'Breadcrumbs' && breadcrumbs) {
    const breadcrumbSchema = {
      "@context": "https://schema.org",
      "@type": "BreadcrumbList",
      "itemListElement": breadcrumbs.map((crumb, index) => ({
        "@type": "ListItem",
        "position": index + 1,
        "name": crumb.name,
        "item": crumb.url
      }))
    };

    return (
      <script
        id="schema-breadcrumb-list"
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbSchema) }}
      />
    );
  }

  return null;
}
